function initials(name){return name.split(" ").filter(Boolean).slice(0,2).map(x=>x[0]).join("").toUpperCase();}
function escapeHtml(str){return String(str??"").replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;");}
async function api(url,options={}){const r=await fetch(url,options);if(!r.ok)throw new Error(await r.text());return await r.json();}
async function loadData(){state.settings=await api('/api/settings');state.applications=await api('/api/applications');state.reviews=await api('/api/reviews');state.allReviews=await api('/api/reviews?all=1');render();}
function setPage(p){state.page=p;render();}
function teacherPhotoHtml(name){const src=teacherPhotos[name];return src?`<img class="teacher-photo" src="${src}" alt="${escapeHtml(name)}">`:`<div class="teacher-fallback">${escapeHtml(initials(name))}</div>`;}
function sectionTitle(b,t,d){return `<div class="section-title"><div class="badge">${b}</div><h2>${t}</h2><p>${d}</p></div>`;}
function heroHtml(){const s=state.settings;return `<section class="hero"><div class="container hero-grid"><div><div class="badge">Полная серверная версия v2</div><h1>${escapeHtml(s.centerName)} — ${escapeHtml(s.heroTitle)}</h1><div class="slogan-en">${escapeHtml(s.sloganEn)}</div><div class="slogan-ru">${escapeHtml(s.sloganRu)}</div><div class="lead">${escapeHtml(s.heroText)}</div><div class="actions"><button class="btn primary" onclick="setPage('level-test')">Определить уровень</button><button class="btn" onclick="setPage('programs')">Открыть программы</button></div><div class="stats"><div class="card pad"><strong>6</strong><div class="small">языков в тесте</div></div><div class="card pad"><strong>50</strong><div class="small">вопросов на язык</div></div><div class="card pad"><strong>`+Object.keys(teacherPhotos).length+`</strong><div class="small">карточек с фото</div></div><div class="card pad"><strong>Работает</strong><div class="small">серверная форма</div></div></div></div><div class="card pad"><div class="panel-dark"><p>Что исправлено</p><h3 style="margin:10px 0 0;font-size:30px">Тесты и карточки</h3><div class="panel-grid"><div class="mini-pill">50 вопросов на язык</div><div class="mini-pill">A1 — C2</div><div class="mini-pill">Рабочие карточки</div><div class="mini-pill">Реальные фото</div></div></div></div></div></section>`;}
function aboutHtml(){return `<section class="section"><div class="container">${sectionTitle('О центре','Образовательный центр FLEPP имени профессора Фузайлова','Мы открываем двери к знаниям, языкам и будущему.')}<div class="grid-2" style="margin-top:32px"><div class="card pad"><h3 style="margin:0">История и развитие</h3><p class="lead" style="font-size:16px">Центр основан в 2016 году и объединяет филиалы в Бустоне, Унчи, Конибодоме и Овчикалаче.</p></div><div class="card pad"><h3 style="margin:0">Контакты</h3><div class="small" style="margin-top:12px">Телефон директора: ${escapeHtml(state.settings.directorPhone)}</div><div class="small">Время работы: ${escapeHtml(state.settings.workTime)}</div></div></div></div></section>`;}
function programsHtml(){const list=state.selectedProgramCategory==='languages'?languagePrograms:subjectPrograms;const selected=list.find(x=>x.key===state.selectedProgramKey)||list[0];const related=teachers.filter(t=>(t.directions||[]).includes(selected.key));return `<section class="section soft"><div class="container">${sectionTitle('Программы','Каталог программ открывается корректно','Можно переключаться между языками и предметами, открывать информацию о курсе и просматривать преподавателей направления.')}<div class="actions" style="margin-top:24px"><button class="btn ${state.selectedProgramCategory==='languages'?'dark':''}" onclick="switchProgramCategory('languages')">Языки</button><button class="btn ${state.selectedProgramCategory==='subjects'?'dark':''}" onclick="switchProgramCategory('subjects')">Предметы</button></div><div class="grid-2" style="margin-top:32px;grid-template-columns:0.9fr 1.1fr"><div class="card pad"><div class="stack">${list.map(item=>`<button class="program-list-btn ${selected.key===item.key?'active':''}" onclick="selectProgram('${escapeHtml(item.key)}')"><div style="font-weight:700">${escapeHtml(item.title)}</div><div class="small">${escapeHtml(item.price)}</div></button>`).join('')}</div></div><div class="card pad"><h3 style="margin:0;font-size:30px">${escapeHtml(selected.title)}</h3><p class="lead" style="font-size:16px">${escapeHtml(selected.description)}</p><div class="grid-2">${(selected.details||[]).map(d=>`<div class="notice">${escapeHtml(d)}</div>`).join('')}</div><div style="margin-top:22px"><h4 style="margin:0 0 12px">Преподаватели направления</h4><div class="stack">${related.length?related.map(t=>`<div class="notice"><strong>${escapeHtml(t.name)}</strong><br><span class="small">${escapeHtml(t.role)}</span></div>`).join(''):`<div class="notice">Для этого направления преподаватели пока не привязаны отдельно.</div>`}</div></div></div></div></div></section>`;}
function levelResult(score){if(score<=8)return'A1';if(score<=16)return'A2';if(score<=25)return'B1';if(score<=34)return'B2';if(score<=42)return'C1';return'C2';}
function levelTestHtml(){const langs=Object.keys(levelTests);const questions=levelTests[state.testLanguage];const score=questions.reduce((a,q,i)=>a+(state.testAnswers[i]===q.correct?1:0),0);return `<section class="section"><div class="container">${sectionTitle('Тест уровня','50 вопросов по каждому языку от A1 до C2','Теперь тест уровня стал полноценным: у каждого языка 50 вопросов.')}<div class="actions" style="margin-top:24px">${langs.map(l=>`<button class="btn ${state.testLanguage===l?'dark':''}" onclick="selectTestLanguage('${escapeHtml(l)}')">${escapeHtml(l)}</button>`).join('')}</div><div class="card pad" style="margin-top:24px"><h3 style="margin:0">Тест по языку: ${escapeHtml(state.testLanguage)}</h3><p class="small" style="margin-top:10px">Всего вопросов: 50. Отвечено: ${Object.keys(state.testAnswers).length}/50.</p><div class="stack" style="margin-top:18px">${questions.map((q,qi)=>`<div class="notice"><div style="font-weight:700">${qi+1}. [${q.level}] ${escapeHtml(q.q)}</div><div class="stack" style="margin-top:12px">${q.a.map((o,oi)=>`<button class="program-list-btn ${state.testAnswers[qi]===oi?'active':''}" onclick="chooseAnswer(${qi},${oi})">${escapeHtml(o)}</button>`).join('')}</div></div>`).join('')}</div><div class="actions" style="margin-top:20px"><button class="btn primary" onclick="submitTest()">Показать результат</button><button class="btn" onclick="resetTest()">Сбросить</button></div>${state.testSubmitted?`<div class="notice" style="margin-top:18px"><strong>Предварительно: ${levelResult(score)}</strong><br><span class="small">Правильных ответов: ${score} из 50.</span></div>`:''}</div></div></section>`;}
function reviewsHtml(){return `<section class="section"><div class="container">${sectionTitle('Отзывы','Отзывы с обязательным выбором провайдера','Оставить отзыв можно только после выбора Google или Yandex.')}<div class="grid-2" style="margin-top:32px;grid-template-columns:0.9fr 1.1fr"><div class="card pad"><div class="actions"><button class="btn ${state.reviewProvider==='Google'?'dark':''}" onclick="chooseProvider('Google')">Google</button><button class="btn ${state.reviewProvider==='Yandex'?'dark':''}" onclick="chooseProvider('Yandex')">Yandex</button></div><form class="stack" style="margin-top:16px" onsubmit="submitReview(event)"><input class="input" name="author" placeholder="Ваше имя" required><select class="select" name="rating"><option value="5">5</option><option value="4">4</option><option value="3">3</option><option value="2">2</option><option value="1">1</option></select><textarea class="textarea" name="text" placeholder="Ваш отзыв" required></textarea><button class="btn primary" type="submit">Оставить отзыв</button></form><div id="reviewMessage" class="small" style="margin-top:12px"></div></div><div class="stack">${state.reviews.map(r=>`<div class="card pad"><strong>${escapeHtml(r.author)}</strong><div class="small">через ${escapeHtml(r.provider)}</div><p class="lead" style="font-size:16px">${escapeHtml(r.text)}</p></div>`).join('')}</div></div></div></section>`;}
function teamHtml(){return `<section class="section"><div class="container">${sectionTitle('Команда','Карточки преподавателей открываются и показывают фото','Для загруженных преподавателей карточки теперь содержат реальные фотографии.')}<div class="grid-3" style="margin-top:32px">${teachers.map((t,i)=>`<div class="card pad"><div class="teacher-row">${teacherPhotoHtml(t.name)}<div><h3 style="margin:0;font-size:20px">${escapeHtml(t.name)}</h3><div class="small" style="margin-top:8px">${escapeHtml(t.role)}</div></div></div><button class="btn" style="width:100%;margin-top:18px" onclick="openTeacher(${i})">Открыть карточку</button></div>`).join('')}</div></div></section>`;}
function contactsHtml(){const s=state.settings;const whatsappHref=`https://wa.me/${(s.whatsapp||'').replace(/[^\d]/g,'')}`;return `<section class="section"><div class="container">${sectionTitle('Контакты','Связь и заявка','Форма заявки подключена к серверу.')}<div class="grid-2" style="margin-top:32px"><div class="card pad"><div class="stack"><div class="notice">Телефон директора: ${escapeHtml(s.directorPhone)}</div><div class="notice">WhatsApp: <a href="${escapeHtml(whatsappHref)}" target="_blank">${escapeHtml(s.whatsapp)}</a></div><div class="notice">Telegram: <a href="${escapeHtml(s.telegram)}" target="_blank">Перейти</a></div><div class="notice">Instagram: <a href="${escapeHtml(s.instagram)}" target="_blank">Перейти</a></div></div></div><div class="card pad"><form class="stack" onsubmit="submitApplication(event)"><input class="input" name="name" placeholder="Ваше имя" required><input class="input" name="phone" placeholder="Телефон" required><input class="input" name="course" placeholder="Интересующий курс"><input class="input" name="branch" placeholder="Филиал"><textarea class="textarea" name="note" placeholder="Комментарий"></textarea><button class="btn primary" type="submit">Отправить заявку</button></form><div id="formMessage" class="small" style="margin-top:12px"></div></div></div></div></section>`;}
function adminHtml(){if(!state.adminAuthorized)return `<section class="section"><div class="container" style="max-width:560px"><div class="card pad"><input id="adminPin" class="input" placeholder="Введите PIN"><button class="btn primary" style="margin-top:12px" onclick="adminLogin()">Войти</button><div id="adminLoginMessage" class="small" style="margin-top:12px">Стартовый PIN: 1234</div></div></div></section>`;const s=state.settings;return `<section class="section"><div class="container">${sectionTitle('Админ','Управление сайтом и заявками','Здесь можно менять настройки сайта, просматривать заявки и модерировать отзывы.')}<div class="grid-2" style="margin-top:32px"><div class="card pad"><div class="stack"><input id="setCenterName" class="input" value="${escapeHtml(s.centerName)}"><input id="setHeroTitle" class="input" value="${escapeHtml(s.heroTitle)}"><textarea id="setHeroText" class="textarea">${escapeHtml(s.heroText)}</textarea><input id="setSloganEn" class="input" value="${escapeHtml(s.sloganEn)}"><input id="setSloganRu" class="input" value="${escapeHtml(s.sloganRu)}"><input id="setDirectorPhone" class="input" value="${escapeHtml(s.directorPhone)}"><input id="setWhatsapp" class="input" value="${escapeHtml(s.whatsapp)}"><input id="setTelegram" class="input" value="${escapeHtml(s.telegram)}"><input id="setInstagram" class="input" value="${escapeHtml(s.instagram)}"><input id="setWorkTime" class="input" value="${escapeHtml(s.workTime)}"><input id="setAdminPin" class="input" value="${escapeHtml(s.adminPin)}"><button class="btn primary" onclick="saveSettings()">Сохранить настройки</button><div id="settingsMessage" class="small"></div></div></div><div class="stack"><div class="card pad"><h3 style="margin:0">Заявки</h3><div class="stack" style="margin-top:16px">${state.applications.length?state.applications.map(app=>`<div class="notice"><strong>${escapeHtml(app.name)}</strong><br>${escapeHtml(app.phone)}<br>Курс: ${escapeHtml(app.course||'не указан')}<br><button class="btn" style="margin-top:8px" onclick="deleteApplication('${escapeHtml(app.id)}')">Удалить</button></div>`).join(''):`<div class="notice">Пока заявок нет.</div>`}</div></div><div class="card pad"><h3 style="margin:0">Отзывы на модерации</h3><div class="stack" style="margin-top:16px">${state.allReviews.filter(r=>!r.approved).length?state.allReviews.filter(r=>!r.approved).map(r=>`<div class="notice"><strong>${escapeHtml(r.author)}</strong><br>${escapeHtml(r.text)}<br><div class="actions" style="margin-top:8px"><button class="btn primary" onclick="approveReview('${escapeHtml(r.id)}')">Одобрить</button><button class="btn" onclick="deleteReview('${escapeHtml(r.id)}')">Удалить</button></div></div>`).join(''):`<div class="notice">Нет новых отзывов на модерации.</div>`}</div></div></div></div></div></section>`;}
function teacherModalHtml(){if(state.selectedTeacher===null)return '';const t=teachers[state.selectedTeacher];return `<div class="modal" onclick="closeTeacher(event)"><div class="modal-card" onclick="event.stopPropagation()"><div style="display:flex;justify-content:space-between;gap:16px;align-items:start"><div class="teacher-row">${teacherPhotoHtml(t.name)}<div><h3 style="margin:0">${escapeHtml(t.name)}</h3><div class="small" style="margin-top:8px">${escapeHtml(t.role)}</div></div></div><button class="btn" onclick="state.selectedTeacher=null;render()">Закрыть</button></div><div class="notice" style="margin-top:18px">Карточка преподавателя открыта корректно.${teacherPhotos[t.name]?' Фотография подключена.':' Фото пока не добавлено.'}</div></div></div>`;}
function footerHtml(){const s=state.settings;return `<footer class="footer"><div class="container grid-2"><div><div class="brand"><div class="logo">F</div><div><div style="font-weight:700">FLEPP</div><div class="small">имени профессора Фузайлова</div></div></div><p class="small" style="margin-top:14px">Полная серверная версия: 50 вопросов на язык, рабочие карточки преподавателей и реальные фотографии.</p></div><div class="stack"><div class="notice">Телефон директора: ${escapeHtml(s.directorPhone)}</div><div class="notice">Время работы: ${escapeHtml(s.workTime)}</div></div></div></footer>`;}
function layout(content){return `<header class="topbar"><div class="container nav"><div class="brand"><div class="logo">F</div><div><div style="font-weight:700">FLEPP</div><div class="small">имени профессора Фузайлова</div></div></div><nav class="menu">${[['home','Главная'],['programs','Программы'],['level-test','Тест уровня'],['reviews','Отзывы'],['team','Команда'],['contacts','Контакты'],['admin','Админ']].map(([k,l])=>`<button class="${state.page===k?'active':''}" onclick="setPage('${k}')">${l}</button>`).join('')}</nav></div></header>${content}${footerHtml()}${teacherModalHtml()}`;}
function render(){if(!state.settings)return;let content='';if(state.page==='home')content=heroHtml()+aboutHtml();if(state.page==='programs')content=programsHtml();if(state.page==='level-test')content=levelTestHtml();if(state.page==='reviews')content=reviewsHtml();if(state.page==='team')content=teamHtml();if(state.page==='contacts')content=contactsHtml();if(state.page==='admin')content=adminHtml();document.getElementById('app').innerHTML=layout(content);}
function switchProgramCategory(category){state.selectedProgramCategory=category;state.selectedProgramKey=category==='languages'?languagePrograms[0].key:subjectPrograms[0].key;render();}
function selectProgram(key){state.selectedProgramKey=key;render();}
function selectTestLanguage(lang){state.testLanguage=lang;state.testAnswers={};state.testSubmitted=false;render();}
function chooseAnswer(qi,oi){state.testAnswers[qi]=oi;render();}
function submitTest(){state.testSubmitted=true;render();}
function resetTest(){state.testAnswers={};state.testSubmitted=false;render();}
async function submitApplication(e){e.preventDefault();const fd=new FormData(e.target);const payload=Object.fromEntries(fd.entries());const msg=document.getElementById('formMessage');msg.textContent='Отправка...';try{await api('/api/applications',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});state.applications=await api('/api/applications');msg.textContent='Заявка сохранена на сервере.';e.target.reset();}catch{msg.textContent='Ошибка отправки заявки.';}}
function chooseProvider(provider){state.reviewProvider=provider;render();const msg=document.getElementById('reviewMessage');if(msg)msg.textContent=`Выбран провайдер: ${provider}.`;}
async function submitReview(e){e.preventDefault();const msg=document.getElementById('reviewMessage');if(!state.reviewProvider){msg.textContent='Сначала выберите Google или Yandex.';return;}const fd=new FormData(e.target);const payload=Object.fromEntries(fd.entries());payload.provider=state.reviewProvider;msg.textContent='Отправка...';try{await api('/api/reviews',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});state.reviews=await api('/api/reviews');state.allReviews=await api('/api/reviews?all=1');msg.textContent='Отзыв отправлен. После модерации он появится в общем списке.';e.target.reset();}catch{msg.textContent='Ошибка отправки отзыва.';}}
function adminLogin(){const pin=document.getElementById('adminPin').value;const msg=document.getElementById('adminLoginMessage');if(pin===state.settings.adminPin){state.adminAuthorized=true;render();}else msg.textContent='Неверный PIN.';}
async function saveSettings(){const payload={centerName:document.getElementById('setCenterName').value,heroTitle:document.getElementById('setHeroTitle').value,heroText:document.getElementById('setHeroText').value,sloganEn:document.getElementById('setSloganEn').value,sloganRu:document.getElementById('setSloganRu').value,directorPhone:document.getElementById('setDirectorPhone').value,whatsapp:document.getElementById('setWhatsapp').value,telegram:document.getElementById('setTelegram').value,instagram:document.getElementById('setInstagram').value,workTime:document.getElementById('setWorkTime').value,adminPin:document.getElementById('setAdminPin').value};await api('/api/settings',{method:'PUT',headers:{'Content-Type':'application/json'},body:JSON.stringify(payload)});state.settings=await api('/api/settings');document.getElementById('settingsMessage').textContent='Настройки сохранены.';}
async function deleteApplication(id){await api(`/api/applications/${id}`,{method:'DELETE'});state.applications=await api('/api/applications');render();}
async function approveReview(id){await api(`/api/reviews/${id}/approve`,{method:'PUT'});state.reviews=await api('/api/reviews');state.allReviews=await api('/api/reviews?all=1');render();}
async function deleteReview(id){await api(`/api/reviews/${id}`,{method:'DELETE'});state.reviews=await api('/api/reviews');state.allReviews=await api('/api/reviews?all=1');render();}
function openTeacher(i){state.selectedTeacher=i;render();}
function closeTeacher(e){if(e.target.classList.contains('modal')){state.selectedTeacher=null;render();}}
window.setPage=setPage;window.switchProgramCategory=switchProgramCategory;window.selectProgram=selectProgram;window.selectTestLanguage=selectTestLanguage;window.chooseAnswer=chooseAnswer;window.submitTest=submitTest;window.resetTest=resetTest;window.submitApplication=submitApplication;window.chooseProvider=chooseProvider;window.submitReview=submitReview;window.adminLogin=adminLogin;window.saveSettings=saveSettings;window.deleteApplication=deleteApplication;window.approveReview=approveReview;window.deleteReview=deleteReview;window.openTeacher=openTeacher;window.closeTeacher=closeTeacher;loadData();
